<?php
require_once dirname(__DIR__) . '/includes/functions.php';
employeePortalGuard();$user=currentUser();$pdo=getDB();$employee=employeeForCurrentUser($pdo,$user);if(!$employee){siteHeader('My Expenses','login');echo '<div class="alert alert-warning">No employee profile is linked to your email.</div>';siteFooter();exit;}
if($_SERVER['REQUEST_METHOD']==='POST'){try{$number=nextScopedDocumentNumber($pdo,'employee_expense_claim',setting('employee_expense_prefix','EXPCL'),operationalScope($pdo));$amount=max(0,(float)$_POST['amount']);$tax=max(0,(float)($_POST['tax']??0));$pdo->prepare('INSERT INTO '.table('employee_expense_claims').' (claim_number,employee_id,claim_date,total_amount,status,approval_status,notes) VALUES (?,?,?,?,"draft","pending",?)')->execute([$number,(int)$employee['id'],trim((string)$_POST['claim_date'])?:date('Y-m-d'),$amount+$tax,trim((string)$_POST['notes'])]);$claimId=(int)$pdo->lastInsertId();$upload=uploadAdminDocument('receipt','employee-expenses');$receipt=$upload['stored_path']??null;$pdo->prepare('INSERT INTO '.table('employee_expense_claim_items').' (employee_expense_claim_id,category,description,amount,tax,receipt_path) VALUES (?,?,?,?,?,?)')->execute([$claimId,trim((string)$_POST['category']),trim((string)$_POST['description']),$amount,$tax,$receipt]);flash('success','Expense claim submitted.');}catch(Throwable $e){flash('error',$e->getMessage());}redirect(SITE_URL.'/employee/expenses.php');}
$rows=$pdo->prepare('SELECT * FROM '.table('employee_expense_claims').' WHERE employee_id=? ORDER BY created_at DESC');$rows->execute([(int)$employee['id']]);$rows=$rows->fetchAll();
siteHeader('My Expenses','login');
?>
<h1 class="mb-4">My Expenses</h1><div class="row g-4"><div class="col-lg-5"><form method="post" enctype="multipart/form-data" class="form-card"><h2 class="h4">Submit Expense</h2><input class="form-control mb-3" type="date" name="claim_date" value="<?php echo date('Y-m-d'); ?>"><input class="form-control mb-3" name="category" placeholder="Fuel, travel, tools, customer visit"><input class="form-control mb-3" name="description" placeholder="Description"><input class="form-control mb-3" type="number" step="0.01" name="amount" placeholder="Amount"><input class="form-control mb-3" type="number" step="0.01" name="tax" placeholder="Tax"><input class="form-control mb-3" type="file" name="receipt"><textarea class="form-control mb-3" name="notes" rows="3" placeholder="Notes"></textarea><button class="btn btn-brand">Submit Claim</button></form></div><div class="col-lg-7"><div class="table-card table-responsive"><h2 class="h5">Claims</h2><table class="table"><thead><tr><th>Claim</th><th>Date</th><th>Total</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r): ?><tr><td><strong><?php echo esc($r['claim_number']); ?></strong></td><td><?php echo esc($r['claim_date']); ?></td><td><?php echo money($r['total_amount']); ?></td><td><span class="badge bg-<?php echo esc(statusTone($r['approval_status'])); ?>"><?php echo esc($r['approval_status']); ?></span></td></tr><?php endforeach; ?></tbody></table></div></div></div>
<?php siteFooter(); ?>